import{_ as e,o as l,c as a,a2 as n}from"./chunks/framework.BQ1gajhD.js";const u=JSON.parse('{"title":"祈年殿","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/temple-of-heaven/qinian-dian.md","filePath":"landmarks/temple-of-heaven/qinian-dian.md","lastUpdated":1784720050000}'),i={name:"landmarks/temple-of-heaven/qinian-dian.md"};function r(d,t,o,s,h,g){return l(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="祈年殿" tabindex="-1">祈年殿 <a class="header-anchor" href="#祈年殿" aria-label="Permalink to &quot;祈年殿&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1769950971259-d9dfb821c7b8?w=1200&amp;q=80" alt="祈年殿"></p><blockquote><p>&quot;三重蓝瓦覆苍穹，二十八柱藏星斗。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>祈年殿是<strong>天坛的主体建筑</strong>，也是整个北京城的标志性符号。它矗立于内坛北部一座三层汉白玉圆台（祈谷坛）之上，是一座圆形三重檐攒尖顶大殿：直径32米，通高38米，上覆三层蓝色琉璃瓦，顶立鎏金宝顶，在古柏与长空的映衬下，恰似一顶从天而降的华盖。</p><p>祈年殿的功能是<strong>孟春祈谷</strong>——每年农历正月上辛日，皇帝在此举行祈谷大典，向上帝祈求五谷丰登、国泰民安。与南部的<a href="/beijing-travel-guide/landmarks/temple-of-heaven/huanqiu-tan.html">圜丘坛</a>（冬至祭天）一北一南，构成天坛祭祀体系的两大核心，中由<a href="/beijing-travel-guide/landmarks/temple-of-heaven/danbi-qiao.html">丹陛桥</a>相连。</p><p>祈年殿始建于明永乐十八年（1420年），初名&quot;大祀殿&quot;，为矩形大殿，合祀天地。嘉靖二十四年（1545年）改建为圆形三重檐的&quot;大享殿&quot;，瓦作青、黄、绿三色，分别象征天、地、万物。清乾隆十六年（1751年）再次大修，将三色瓦统一为纯蓝琉璃瓦，并正式定名&quot;祈年殿&quot;——蓝色，正是天的颜色。</p><p>在中国人的集体记忆中，祈年殿早已超越建筑本身：它与长城、故宫并列，是&quot;中国&quot;二字最直观的视觉符号之一。那抹立于古柏之上的深蓝，既是古代帝王对天的敬畏，也是中式美学&quot;以象尽意&quot;的极致表达。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><p><img src="https://images.unsplash.com/photo-1761160763579-69a51c6ddd33?w=1200&amp;q=80" alt="祈年殿蓝瓦金顶"></p><p>祈年殿最精妙之处，在于<strong>全殿不用大梁与长檩</strong>，仅凭二十八根楠木巨柱和层层斗拱、枋桷支撑起三重穹顶，堪称中国木构建筑的巅峰之作。这二十八根柱子本身就是一部历法：</p><table tabindex="0"><thead><tr><th style="text-align:left;">柱位</th><th style="text-align:left;">名称</th><th style="text-align:center;">数量</th><th style="text-align:left;">象征</th></tr></thead><tbody><tr><td style="text-align:left;">最中央</td><td style="text-align:left;">龙井柱</td><td style="text-align:center;">4根</td><td style="text-align:left;">春夏秋冬四季</td></tr><tr><td style="text-align:left;">中圈</td><td style="text-align:left;">金柱</td><td style="text-align:center;">12根</td><td style="text-align:left;">一年十二个月</td></tr><tr><td style="text-align:left;">外圈</td><td style="text-align:left;">檐柱</td><td style="text-align:center;">12根</td><td style="text-align:left;">一天十二个时辰</td></tr><tr><td style="text-align:left;">合计</td><td style="text-align:left;">—</td><td style="text-align:center;">28根</td><td style="text-align:left;">天上二十八星宿</td></tr></tbody></table><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">规格</th></tr></thead><tbody><tr><td style="text-align:left;">殿体直径</td><td style="text-align:left;">32米</td></tr><tr><td style="text-align:left;">通高（含台基宝顶）</td><td style="text-align:left;">38米</td></tr><tr><td style="text-align:left;">屋顶形制</td><td style="text-align:left;">圆形三重檐攒尖顶</td></tr><tr><td style="text-align:left;">瓦作</td><td style="text-align:left;">三层纯蓝琉璃瓦</td></tr><tr><td style="text-align:left;">宝顶</td><td style="text-align:left;">鎏金宝顶</td></tr><tr><td style="text-align:left;">殿基</td><td style="text-align:left;">三层汉白玉圆台（祈谷坛），高6米</td></tr><tr><td style="text-align:left;">结构特点</td><td style="text-align:left;">无大梁长檩，以柱、枋、斗拱承重</td></tr></tbody></table><p>殿内穹顶中央饰有九龙藻井，金龙盘绕，精美绝伦；地面中心铺一方大理石，天然纹样形似龙凤，与穹顶藻井上下呼应。殿北的皇乾殿则是平时供奉祈谷神牌之处。</p><p>殿前的祈谷坛同样暗藏&quot;九&quot;数：三层圆台每层台阶九级，栏板数目皆为九的倍数，与南部的<a href="/beijing-travel-guide/landmarks/temple-of-heaven/huanqiu-tan.html">圜丘坛</a>同一数理体系。从坛下仰望，三层蓝瓦逐层收分，宝顶直指苍穹，整座建筑仿佛一个向上收束的祈愿手势。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="雷火焚殿与重建" tabindex="-1">雷火焚殿与重建 <a class="header-anchor" href="#雷火焚殿与重建" aria-label="Permalink to &quot;雷火焚殿与重建&quot;">​</a></h3><p>清光绪十五年（1889年）八月二十四日，一场罕见的雷雨袭击北京，<strong>祈年殿被雷电击中，烈焰冲天，整座大殿连同二十八根楠木巨柱尽数焚毁</strong>。相传殿中珍贵的金丝楠木燃烧时异香弥漫，数里之外皆可闻到。</p><p>光绪帝下旨按原样重建。由于原图纸档案残缺，工匠们全凭记忆与实测，耗时数年（1890年开工，1896年全部竣工），将祈年殿分毫不差地恢复原貌。今日所见的祈年殿，即这次重建的遗构——它既是明代礼制的延续，也是晚清匠作技艺的见证。</p><h3 id="嘉靖改制定圆形" tabindex="-1">嘉靖改制定圆形 <a class="header-anchor" href="#嘉靖改制定圆形" aria-label="Permalink to &quot;嘉靖改制定圆形&quot;">​</a></h3><p>明初天地合祀，大祀殿是方形大殿。嘉靖帝笃信道教、讲究礼制，力排众议推行天地分祀，并把大殿改为圆形三重檐——&quot;天圆&quot;之意从此凝固在建筑形制之中。这场&quot;大礼议&quot;之后的礼制改革，意外成就了天坛今日的经典轮廓。</p><h3 id="深山楠木万里来" tabindex="-1">深山楠木万里来 <a class="header-anchor" href="#深山楠木万里来" aria-label="Permalink to &quot;深山楠木万里来&quot;">​</a></h3><p>二十八根承重巨柱均为珍贵的金丝楠木，其中尤以中央四根龙井柱最为难得。明清时期优质楠木产于川、黔、滇深山密林之中，采伐一根大木往往&quot;入山一千，出山五百&quot;——伐木工半数殒于途。巨木经水路辗转数年方能抵京，故民间有&quot;一根楠木一两金&quot;之说。祈年殿的庄严背后，是万里山林与无数人力。</p><h2 id="最佳游览季节" tabindex="-1">最佳游览季节 <a class="header-anchor" href="#最佳游览季节" aria-label="Permalink to &quot;最佳游览季节&quot;">​</a></h2><ul><li><strong>春季</strong>（3-5月）：坛内丁香、二月兰盛开，蓝瓦与花影相映</li><li><strong>秋季</strong>（9-11月）：古柏苍翠、天空澄澈，是拍摄蓝瓦金顶的黄金期</li><li><strong>雪后</strong>：白雪覆坛、蓝瓦如洗，祈年殿呈现出最接近古画的气质</li></ul><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>二十八柱历法密码</strong>：数清四季、十二月、十二时辰、二十八宿的象征体系，这是读懂中国古代时间观的一把钥匙。</li><li><strong>三层蓝瓦与鎏金宝顶</strong>：天坛区别于紫禁城黄瓦的核心视觉符号，晴天时蓝瓦与天空几乎同色。</li><li><strong>九龙藻井与龙凤石</strong>：殿内仰观穹顶藻井，俯察地面龙凤纹大理石，上下成趣。</li><li><strong>祈谷坛三层圆台</strong>：环行台基可平视殿身细节，也是拍摄祈年殿全景的最佳高度。</li><li><strong>祈年门与皇乾殿</strong>：殿前祈年门为明代原构，殿后皇乾殿供奉神牌，别错过。</li></ol><h2 id="最佳拍照点" tabindex="-1">最佳拍照点 <a class="header-anchor" href="#最佳拍照点" aria-label="Permalink to &quot;最佳拍照点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">机位</th><th style="text-align:left;">画面</th><th style="text-align:left;">建议时间</th></tr></thead><tbody><tr><td style="text-align:left;">祈年门内正面台阶</td><td style="text-align:left;">殿身全景，对称构图</td><td style="text-align:left;">上午8:00-10:00顺光</td></tr><tr><td style="text-align:left;">祈谷坛台基外圈</td><td style="text-align:left;">蓝瓦与宝顶局部特写</td><td style="text-align:left;">晴日全天</td></tr><tr><td style="text-align:left;">皇乾殿北侧回望</td><td style="text-align:left;">古柏掩映中的圆殿侧影</td><td style="text-align:left;">下午斜阳</td></tr><tr><td style="text-align:left;">东配殿前长焦</td><td style="text-align:left;">压缩古柏与殿身，突出纵深感</td><td style="text-align:left;">清晨低角度阳光</td></tr></tbody></table><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ol><li><strong>联票方可入内院</strong>：祈年殿区域需持联票（28元）或另购景点票，仅凭10元门票只能远观。</li><li><strong>最佳拍摄时间</strong>：清晨8:00开门即入，游客最少；逆光时蓝瓦呈深宝石色，顺光时则清亮。</li><li><strong>绕殿三圈看细节</strong>：从台基外圈、台基上、殿门处三个层次观赏，空间感受截然不同。</li><li><strong>顺路游皇乾殿</strong>：祈年殿北的皇乾殿陈列祭祀礼仪复原场景，常被游客忽略。</li><li><strong>向北出园</strong>：看完祈年殿可经天坛北门出，衔接地铁或前往雍和宫方向。</li><li><strong>殿内勿错过数字</strong>：数柱、数瓦当、看藻井，带着&quot;二十八宿&quot;的线索进殿，收获远超走马观花。</li></ol><h2 id="相关景点" tabindex="-1">相关景点 <a class="header-anchor" href="#相关景点" aria-label="Permalink to &quot;相关景点&quot;">​</a></h2><ul><li><a href="/beijing-travel-guide/landmarks/temple-of-heaven/danbi-qiao.html">丹陛桥</a>：祈年殿前的360米神路，由此南下即达</li><li><a href="/beijing-travel-guide/landmarks/temple-of-heaven/huanqiu-tan.html">圜丘坛</a>：神路南端的冬至祭天圆坛，与祈年殿南北呼应</li><li><a href="/beijing-travel-guide/landmarks/temple-of-heaven/huangqiong-yu.html">皇穹宇与回音壁</a>：神路中段西侧的声学奇观</li><li><a href="/beijing-travel-guide/landmarks/temple-of-heaven/zhai-gong.html">斋宫</a>：位于祈年殿西南的皇帝斋戒之所</li></ul><hr><p><strong>📍 位置</strong>：天坛内坛北部中轴线（丹陛桥北端） <strong>⏱️ 建议游览</strong>：40-60分钟 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/temple-of-heaven/">天坛概览</a></p>',35)])])}const x=e(i,[["render",r]]);export{u as __pageData,x as default};
